exercises.solution:
def tally(items)
  counts = Hash.new(0)
  items.each { |x| counts[x] += 1 }
  counts
end

def lines(dossier)
  out = []
  dossier.each_pair { |key, value| out << "#{key}: #{value}" }
  out
end

tests.code:
lines = stdout().split("\n").map { |l| l.strip }
assert(lines.include?("lain"), "lain should be printed")
assert(!lines.include?("akira"), "only the winner should be printed, not akira")
